/**
 * lunr.js - Lightweight full-text search library for client-side applications.
 * 
 * This is a placeholder stub. In production, replace this file with the real
 * lunr.js library from: https://unpkg.com/lunr/lunr.min.js
 * 
 * The actual library is ~8KB minified+gzipped and provides full-text search
 * with stemming, tokenization, and TF-IDF ranking.
 */
(function () {
  "use strict";

  var lunr = function (config) {
    var builder = new lunr.Builder();
    builder.pipeline.add(lunr.trimmer);
    config.call(builder, builder);
    return builder.build();
  };

  lunr.Builder = function () {
    this._ref = "id";
    this._fields = [];
    this._documents = [];
    this.pipeline = { add: function () {} };
  };

  lunr.Builder.prototype.ref = function (ref) {
    this._ref = ref;
  };

  lunr.Builder.prototype.field = function (field) {
    this._fields.push(field);
  };

  lunr.Builder.prototype.add = function (doc) {
    this._documents.push(doc);
  };

  lunr.Builder.prototype.build = function () {
    var fields = this._fields;
    var ref = this._ref;
    var documents = this._documents;

    return {
      search: function (query) {
        if (!query || !query.trim()) return [];
        var terms = query.toLowerCase().trim().split(/\s+/);
        var results = [];

        documents.forEach(function (doc) {
          var match = terms.some(function (term) {
            return fields.some(function (field) {
              var value = (doc[field] || "").toLowerCase();
              return value.indexOf(term) !== -1;
            });
          });
          if (match) {
            results.push({ ref: doc[ref] });
          }
        });

        return results;
      }
    };
  };

  lunr.trimmer = function (token) {
    return token;
  };

  if (typeof window !== "undefined") {
    window.lunr = lunr;
  }
  if (typeof module !== "undefined" && module.exports) {
    module.exports = lunr;
  }
})();
